# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

typedef struct FileHandleNode {
    int fd;
    char* filename;
    struct FileHandleNode* next;
} FileHandleNode;

typedef struct {
    FileHandleNode* head;
    int count;
    int is_initialized;
} FileHandleList;

FileHandleList* create_file_handle_list() {
    FileHandleList* list = (FileHandleList*)malloc(sizeof(FileHandleList));
    if (!list) {
        return NULL;
    }
    list->head = NULL;
    list->count = 0;
    list->is_initialized = 1;
    return list;
}

int add_file_handle(FileHandleList* list, int fd, const char* filename) {
    if (!list || !list->is_initialized) {
        return -1;
    }
    
    FileHandleNode* node = (FileHandleNode*)malloc(sizeof(FileHandleNode));
    if (!node) {
        return -1;
    }
    
    node->fd = fd;
    node->filename = NULL;
    
    if (filename) {
        node->filename = (char*)malloc(strlen(filename) + 1);
        if (!node->filename) {
            free(node);
            return -1;
        }
        strcpy(node->filename, filename);
    }
    
    node->next = list->head;
    list->head = node;
    list->count++;
    
    return 0;
}

int remove_file_handle(FileHandleList* list, int fd) {
    if (!list || !list->is_initialized || !list->head) {
        return -1;
    }
    
    FileHandleNode* current = list->head;
    FileHandleNode* prev = NULL;
    
    while (current) {
        if (current->fd == fd) {
            if (prev) {
                prev->next = current->next;
            } else {
                list->head = current->next;
            }
            
            if (current->fd >= 0) {
                close(current->fd);
            }
            
            if (current->filename) {
                free(current->filename);
            }
            
            free(current);
            list->count--;
            return 0;
        }
        
        prev = current;
        current = current->next;
    }
    
    return -1;
}

void cleanup_file_handle_list(FileHandleList* list) {
    if (!list) {
        return;
    }
    
    if (!list->is_initialized) {
        return;
    }
    
    FileHandleNode* current = list->head;
    FileHandleNode* next;
    
    while (current) {
        next = current->next;
        
        if (current->fd >= 0) {
            close(current->fd);
        }
        
        if (current->filename) {
            free(current->filename);
        }
        
        free(current);
        current = next;
    }
    
    list->head = NULL;
    list->count = 0;
    list->is_initialized = 0;
}

void destroy_file_handle_list(FileHandleList* list) {
    if (!list) {
        return;
    }
    
    cleanup_file_handle_list(list);
    free(list);
}

int get_file_handle_count(FileHandleList* list) {
    if (!list || !list->is_initialized) {
        return -1;
    }
    return list->count;
}

int find_file_handle(FileHandleList* list, int fd) {
    if (!list || !list->is_initialized) {
        return 0;
    }
    
    FileHandleNode* current = list->head;
    while (current) {
        if (current->fd == fd) {
            return 1;
        }
        current = current->next;
    }
    
    return 0;
}

void print_file_handles(FileHandleList* list) {
    if (!list || !list->is_initialized) {
        printf("List is not initialized\n");
        return;
    }
    
    printf("File Handle List (count: %d):\n", list->count);
    
    FileHandleNode* current = list->head;
    while (current) {
        printf("  FD: %d, Filename: %s\n", 
               current->fd, 
               current->filename ? current->filename : "(null)");
        current = current->next;
    }
}

int main() {
    FileHandleList* list = create_file_handle_list();
    if (!list) {
        fprintf(stderr, "Failed to create file handle list\n");
        return 1;
    }
    
    add_file_handle(list, 3, "file1.txt");
    add_file_handle(list, 4, "file2.txt");
    add_file_handle(list, 5, "file3.txt");
    
    printf("After adding 3 handles:\n");
    print_file_handles(list);
    printf("\n");
    
    remove_file_handle(list, 4);
    
    printf("After removing FD 4:\n");
    print_file_handles(list);
    printf("\n");
    
    printf("Calling cleanup for the first time...\n");
    cleanup_file_handle_list(list);
    print_file_handles(list);
    printf("\n");
    
    printf("Calling cleanup for the second time (should be safe)...\n");
    cleanup_file_handle_list(list);
    print_file_handles(list);
    printf("\n");
    
    destroy_file_handle_list(list);
    
    printf("Program completed successfully\n");
    
    return 0;
}